#include<stdio.h>
int main()
{
    long long int n,m,k,i,p=1,q=1,r;
    scanf("%lld %lld %lld",&n,&m,&k);
    if(k>n-1)
    {
        k=k-n+1;
        p=n;
        q=1;
    }
    else
    {
        printf("%lld 1\n",1+k);
        exit(0);
    }
    r=k/(m-1);
    k=k%(m-1);
    p=n-r+1;
    if(r%2==0)
    {
        q=2;
    }
    else
    {
        q=m;
    }
    if(k>=1)
    {
        k=k-1;
        p=p-1;
    }
    if(k>0)
    {
        if(q==2)
        {
            q=q+k;
        }
        else
        {
            q=q-k;
        }
    }
    printf("%lld %lld\n",p,q);
}

